#!run
import ts from "typescript";
import * as path from "path";

export function getJS(tsfile: string) {
  // get corresponding
  // javascript file
  // based on closest tsconfig
  if(tsfile.endsWith(".js"))return tsfile
  const configPath = ts.findConfigFile(
    path.dirname(tsfile),
    ts.sys.fileExists,
    "tsconfig.json"
  );
  console.log("configPath",configPath)
  if (!configPath) {
    return tsfile.replace(/\.ts$/, ".js");
  }

  const configFile = ts.readConfigFile(configPath, ts.sys.readFile);
  const config = ts.parseJsonConfigFileContent(
    configFile.config,
    ts.sys,
    path.dirname(configPath)
  );
  console.log("config",config)
  const { outDir, rootDir } = config.options;

  if (!outDir) {
    return tsfile.replace(/\.ts$/, ".js");
  }

  const root = rootDir || getCommonDirectory(config.fileNames);//path.dirname(configPath);
  const rel = path.relative(root, tsfile);

  return path.join(outDir, rel).replace(/\.ts$/, ".js");
}
function getCommonDirectory(paths: string[]): string {
  const [first, ...rest] = paths.map(p => path.resolve(p));
  let common = first;
  for (const p of rest) {
    common = commonPath(common, p);
  }
  return common;
}

function commonPath(a: string, b: string): string {
  const aParts = a.split(path.sep);
  const bParts = b.split(path.sep);
  const len = Math.min(aParts.length, bParts.length);
  let i = 0;
  while (i < len && aParts[i] === bParts[i]) {
    i++;
  }
  return aParts.slice(0, i).join(path.sep) || path.sep;
}
export async function main(this:any,path:string,...a:any[]){
  const jsf=getJS(path)
  console.log("js file:",jsf)
  return await this.run(jsf,...a);
}